function validate(args, output) {
    const nums = args[0];
    const n = nums.length;
    if (n < 3) return output === -1;
    if (!Number.isInteger(output)) return false;
    const mn = Math.min(...nums);
    const mx = Math.max(...nums);
    return nums.includes(output) && output !== mn && output !== mx;
}

