class Solution:
    def findNonMinOrMax(self, nums):
        n = len(nums)
        if n < 3:
            return -1
        srt = sorted(nums)
        mn, mx = srt[0], srt[-1]
        for x in nums:
            if x != mn and x != mx:
                return x
        return -1

