class Solution:
    def findNonMinOrMax(self, nums: List[int]) -> int:
        n = len(nums)
        if n < 3:
            return -1
        mn, mx = min(nums), max(nums)
        for x in nums[:3]:
            if x != mn and x != mx:
                return x
        return -1

