var findNonMinOrMax = function(nums) {
    const n = nums.length;
    if (n < 3) return -1;
    let mn = nums[0], mx = nums[0];
    for (const x of nums) {
        if (x < mn) mn = x;
        if (x > mx) mx = x;
    }
    for (let i = 0; i < 3; i++) {
        if (nums[i] !== mn && nums[i] !== mx) return nums[i];
    }
    return -1;
};
